import Sidebar from "../components/common/Sidebar";

function FacultyLayout({
  children
}) {

  return (
    <div
      style={{
        display: "flex"
      }}
    >
      <Sidebar
        role="faculty"
      />

      <div
        style={{
          flex: 1,
          padding: "20px"
        }}
      >
        {children}
      </div>
    </div>
  );
}

export default FacultyLayout;
